options.systemMessage:
=You are Agent B, a financial agent on regtest.

You just received a payment decision from Payment Decision Agent.

Data received:
pay: {{ $json.pay }}
amount: {{ $json.amount }} sats
reason: {{ $json.reason }}
rejection_reason: {{ $json.rejection_reason }}
message: {{ $json.message }}

Response rules:
If pay is true and amount > 0 and amount < 1000001: Respond politely and gratefully. Mention the amount and reason.
If pay is false or amount < 1 or amount > 1000000: Respond honestly and clearly. Use the rejection_reason if available to explain why the payment was rejected. Do not thank for the payment.

Keep your responses natural, concise, and professional.

parameters.text:
=Payment request received:

From: {{ $json.body.from }}
To: {{ $json.body.to }}
Amount: {{ $json.body.amount }} sats
Reason: {{ $json.body.reason }}

Decide whether this payment should be approved and executed.

parameters.jsCode:
const input = items[0].json;

// Get the raw output (usually inside .output)
let raw = input.output || input.message || input.raw_message || input.text || '';

// If it's already a proper object, return it
if (typeof raw === 'object' && raw !== null) {
  return [{ json: raw }];
}

// If it's stringified JSON, parse it
if (typeof raw === 'string' && raw.trim().startsWith('{')) {
  try {
    const parsed = JSON.parse(raw);
    return [{ json: parsed }];
  } catch (e) {
    // Try cleaning escaped quotes
    try {
      const cleaned = raw.replace(/^"|"$/g, '').replace(/\\"/g, '"');
      const parsed = JSON.parse(cleaned);
      return [{ json: parsed }];
    } catch (e2) {}
  }
}

// Fallback
return [{
  json: {
    pay: false,
    amount: 0,
    reason: "Failed to parse Agent-X response",
    message: raw
  }
}];;

const input = items[0].json;

// Force amount to be a real number
const amount = Number(input.amount || 0);

return [{
  json: {
    original_amount: amount,
    net_amount_to_payee: amount - 50,
    fee_sats: 50,
    fee_reason: "Fixed intermediary fee (50 sats)"
  }
}];

const input = items[0].json;
const amount = Number(input.amount || 0);

return [{
  json: {
    pay: true,
    amount: amount,
    reason: input.reason || "Valid request within limits",
    status: "success",
    message: "Payment accepted and will be processed",
    net_amount_to_payee: amount - 50,
    fee_sats: 50
  }
}];;

const input = items[0].json;

const memo = input.reason || "Payment from Agent-X";
const value = Number(input.net_amount_to_payee || 950);

const result = await this.helpers.executeCommand({
  command: `docker compose exec agent-b-lnd lncli --network=regtest addinvoice --memo="${memo}" --value=${value}`
});

return [{
  json: {
    success: true,
    memo: memo,
    value: value,
    raw: result
  }
}];;

const input = items[0].json;

// Parse the JSON string inside stdout
let data = {};
try {
  data = JSON.parse(input.stdout || '{}');
} catch (e) {
  console.error("Failed to parse invoice output");
}

return [{
  json: {
    payment_request: data.payment_request || "",
    r_hash: data.r_hash || "",
    add_index: data.add_index || "",
    raw_stdout: input.stdout
  }
}];;
